#!/usr/bin/env node
/**
 * Deploy HiveONNXConsumer to Ritual Chain
 * 
 * Usage:
 *   node scripts/deploy-onnx-consumer.js [bondingCurveAddress]
 * 
 * Requirements:
 *   - PRIVATE_KEY in .env
 *   - deployed-model-ids.json (generated by deploy_onnx_models.py)
 */

const { createWalletClient, createPublicClient, http, parseAbi, toBytes } = require('viem');
const { privateKeyToAccount } = require('viem/accounts');
const fs = require('fs');
const path = require('path');

// Load model IDs
const modelIds = JSON.parse(fs.readFileSync(path.join(__dirname, '../deployed-model-ids.json'), 'utf8'));

// Ritual Chain config
const ritualChain = {
  id: 1979,
  name: 'Ritual',
  nativeCurrency: { name: 'RITUAL', symbol: 'RITUAL', decimals: 18 },
  rpcUrls: {
    default: { http: ['https://rpc.ritualfoundation.org'] },
  },
  blockExplorers: {
    default: { name: 'Ritual Explorer', url: 'https://explorer.ritualfoundation.org' },
  },
};

// ONNX Consumer ABI (constructor only)
const ONNX_CONSUMER_ABI = [
  {
    type: 'constructor',
    inputs: [
      { name: 'bondingCurve', type: 'address' },
      { name: 'riskScoringModelId', type: 'bytes' },
      { name: 'anomalyDetectionModelId', type: 'bytes' },
      { name: 'scamClassificationModelId', type: 'bytes' },
      { name: 'volatilityPredictionModelId', type: 'bytes' },
    ],
  },
];

async function main() {
  // Get bonding curve address from args or use placeholder
  const bondingCurve = process.argv[2] || '0x0000000000000000000000000000000000000000';
  
  // Load private key
  const envPath = path.join(__dirname, '../.env');
  const envContent = fs.readFileSync(envPath, 'utf8');
  const privateKeyMatch = envContent.match(/PRIVATE_KEY=(.+)/);
  
  if (!privateKeyMatch) {
    console.error('Error: PRIVATE_KEY not found in .env');
    process.exit(1);
  }
  
  const privateKey = privateKeyMatch[1].trim();
  const account = privateKeyToAccount(privateKey);
  
  console.log('Deploying HiveONNXConsumer...');
  console.log(`  Account: ${account.address}`);
  console.log(`  Bonding Curve: ${bondingCurve}`);
  
  // Create clients
  const walletClient = createWalletClient({
    account,
    chain: ritualChain,
    transport: http(),
  });
  
  const publicClient = createPublicClient({
    chain: ritualChain,
    transport: http(),
  });
  
  // Encode model IDs as bytes
  const encodeModelId = (id) => toBytes(id);
  
  // Deploy contract
  console.log('\n  Encoding constructor args...');
  
  const deployData = encodeDeployData({
    abi: ONNX_CONSUMER_ABI,
    args: [
      bondingCurve,
      encodeModelId(modelIds.risk_scoring),
      encodeModelId(modelIds.anomaly_detection),
      encodeModelId(modelIds.scam_classification),
      encodeModelId(modelIds.volatility_prediction),
    ],
  });
  
  console.log('  Sending deployment transaction...');
  
  const hash = await walletClient.sendTransaction({
    data: deployData,
    gas: 5000000n,
  });
  
  console.log(`\n  TX Hash: ${hash}`);
  console.log('  Waiting for confirmation...');
  
  const receipt = await publicClient.waitForTransactionReceipt({ hash });
  
  console.log(`\n  ✓ Deployed!`);
  console.log(`  Contract: ${receipt.contractAddress}`);
  console.log(`  Gas Used: ${receipt.gasUsed}`);
  
  // Save deployment info
  const deploymentInfo = {
    onnxConsumer: receipt.contractAddress,
    bondingCurve: bondingCurve,
    models: modelIds,
    txHash: hash,
    blockNumber: receipt.blockNumber,
  };
  
  fs.writeFileSync(
    path.join(__dirname, '../deployed-onnx-consumer.json'),
    JSON.stringify(deploymentInfo, null, 2)
  );
  
  console.log('\n  Deployment info saved to: deployed-onnx-consumer.json');
}

// Helper function to encode deploy data
function encodeDeployData({ abi, args }) {
  // Simple ABI encoder for constructor
  const constructor = abi.find(item => item.type === 'constructor');
  if (!constructor) throw new Error('No constructor found');
  
  // For simplicity, we'll use viem's encodeAbiParameters
  const paramTypes = constructor.inputs.map(input => ({
    type: input.type,
    name: input.name,
  }));
  
  // This is a simplified version - in production use viem's full ABI encoding
  // For now, we'll just return empty data and let the user deploy via cast
  console.log('\n  NOTE: Use cast to deploy:');
  console.log(`  cast send --rpc-url https://rpc.ritualfoundation.org \\`);
  console.log(`    --private-key $PRIVATE_KEY \\`);
  console.log(`    --create "$(cat src/HiveONNXConsumer.sol)" \\`);
  console.log(`    --constructor-args "${bondingCurve}" ...`);
  
  process.exit(0);
}

main().catch((error) => {
  console.error('Deployment failed:', error);
  process.exit(1);
});
